import React ,{ useState , useEffect } from 'react' ;
import {v4 as uuid} from 'uuid' ;
import './App.css' ;

function App() {
  const [userList,setUserList] = useState([]) ;
  const [user,setUser] = useState({
    id:uuid(),

    message:""
  }) ;


  const fetchUsers = async () => {

      const res = await fetch("http://localhost:5000/users") ;
      const data = await res.json() ;
      setUserList(data) ;
  };


  useEffect(() => {
    fetchUsers() ;
  },[]) ;

const handleChange = (e) => {
  const {name,value} = e.target;
  setUser((prev) => ({
    ...prev, 
    [name] : value

  })) ;
};

const handleSubmit = async (e) =>{
  e.preventDefault() ;
   await fetch ("http://localhost:5000/users",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify(user)
   });
   setUser({
    id:uuid(),
    name:"",
    age:"",
    email:"",
    phone:""
   }) ;
   fetchUsers() ;
   }


   return(
    <div className="app-container">
      <h2>Register User</h2>

      <form onSubmit={handleSubmit}>

        <input type="text" name="name" placeholder="Name" value={user.name} onChange={handleChange} required />
        <input type="number" name="age" placeholder="Age" value={user.age} onChange={handleChange} required />
        <input type="email" name="email" placeholder="Email" value={user.email} onChange={handleChange} required />
        <input type="text" name="phone" placeholder="Phone" value={user.phone} onChange={handleChange} required />
        <button type="submit">Submit</button>
      </form>

      <h3>Users List</h3>

      <ul>
        {userList.map((u) => (
          <li key={u._id}>
            {u.name} - {u.age} - {u.email} - {u.phone}
          </li>
        ))}
      </ul>
    </div>
   )
}

export default App ;
